DROP VIEW IF EXISTS `community_finance_summary`;
CREATE VIEW `community_finance_summary` AS select (select coalesce(sum(case when `jeramoyie1`.`community_savings`.`transaction_type` = 'deposit' then `jeramoyie1`.`community_savings`.`amount` else -`jeramoyie1`.`community_savings`.`amount` end),0) from `community_savings`) AS `total_savings`,(select coalesce(sum(`jeramoyie1`.`community_loans`.`amount`),0) from `community_loans` where `jeramoyie1`.`community_loans`.`status` in ('approved','completed','defaulted')) AS `total_loans_issued`,(select coalesce(sum(`jeramoyie1`.`community_loans`.`interest_amount`),0) from `community_loans` where `jeramoyie1`.`community_loans`.`status` in ('approved','completed','defaulted')) AS `total_interest_earned`,(select coalesce(sum(`jeramoyie1`.`community_loans`.`penalty_accrued`),0) from `community_loans` where `jeramoyie1`.`community_loans`.`penalty_accrued` > 0) AS `total_penalties_collected`,(select count(0) from `community_loans` where `jeramoyie1`.`community_loans`.`status` = 'approved') AS `active_loans_count`,(select count(0) from `community_loans` where `jeramoyie1`.`community_loans`.`status` = 'defaulted') AS `defaulted_loans_count`;

DROP VIEW IF EXISTS `member_financial_summary`;
CREATE VIEW `member_financial_summary` AS select `m`.`id` AS `id`,coalesce((select sum(`jeramoyie1`.`normal_savings`.`amount`) from `normal_savings` where `jeramoyie1`.`normal_savings`.`member_id` = `m`.`id` and `jeramoyie1`.`normal_savings`.`transaction_type` = 'deposit'),0) - coalesce((select sum(`jeramoyie1`.`normal_savings`.`amount`) from `normal_savings` where `jeramoyie1`.`normal_savings`.`member_id` = `m`.`id` and `jeramoyie1`.`normal_savings`.`transaction_type` = 'withdrawal'),0) AS `normal_savings_balance`,coalesce((select sum(`jeramoyie1`.`table_banking_shares`.`amount`) from `table_banking_shares` where `jeramoyie1`.`table_banking_shares`.`member_id` = `m`.`id` and `jeramoyie1`.`table_banking_shares`.`transaction_type` = 'share'),0) - coalesce((select sum(`jeramoyie1`.`table_banking_shares`.`amount`) from `table_banking_shares` where `jeramoyie1`.`table_banking_shares`.`member_id` = `m`.`id` and `jeramoyie1`.`table_banking_shares`.`transaction_type` = 'withdrawal'),0) AS `table_banking_balance`,coalesce((select sum(`jeramoyie1`.`welfare_contributions`.`amount`) from `welfare_contributions` where `jeramoyie1`.`welfare_contributions`.`member_id` = `m`.`id`),0) AS `welfare_balance`,coalesce((select sum(`jeramoyie1`.`weekly_contributions`.`amount`) from `weekly_contributions` where `jeramoyie1`.`weekly_contributions`.`member_id` = `m`.`id` and `jeramoyie1`.`weekly_contributions`.`status` = 'paid'),0) AS `total_weekly_paid`,coalesce((select sum(`jeramoyie1`.`normal_loans`.`amount`) from `normal_loans` where `jeramoyie1`.`normal_loans`.`member_id` = `m`.`id` and `jeramoyie1`.`normal_loans`.`status` in ('approved','active')),0) - coalesce((select sum(`jeramoyie1`.`loan_repayments`.`amount`) from `loan_repayments` where `jeramoyie1`.`loan_repayments`.`member_id` = `m`.`id` and `jeramoyie1`.`loan_repayments`.`loan_type` = 'normal'),0) AS `normal_loans_balance`,coalesce((select sum(`jeramoyie1`.`table_banking_loans`.`amount`) from `table_banking_loans` where `jeramoyie1`.`table_banking_loans`.`member_id` = `m`.`id` and `jeramoyie1`.`table_banking_loans`.`status` in ('approved','active')),0) - coalesce((select sum(`jeramoyie1`.`loan_repayments`.`amount`) from `loan_repayments` where `jeramoyie1`.`loan_repayments`.`member_id` = `m`.`id` and `jeramoyie1`.`loan_repayments`.`loan_type` = 'table_banking'),0) AS `table_banking_loans_balance`,coalesce((select sum(`jeramoyie1`.`uwezo_loans`.`amount`) from `uwezo_loans` where `jeramoyie1`.`uwezo_loans`.`member_id` = `m`.`id` and `jeramoyie1`.`uwezo_loans`.`status` in ('approved','active')),0) - coalesce((select sum(`jeramoyie1`.`loan_repayments`.`amount`) from `loan_repayments` where `jeramoyie1`.`loan_repayments`.`member_id` = `m`.`id` and `jeramoyie1`.`loan_repayments`.`loan_type` = 'uwezo'),0) AS `uwezo_loans_balance`,coalesce((select sum(`jeramoyie1`.`weekly_contributions`.`amount`) from `weekly_contributions` where `jeramoyie1`.`weekly_contributions`.`member_id` = `m`.`id` and `jeramoyie1`.`weekly_contributions`.`status` = 'paid'),0) + (coalesce((select sum(`jeramoyie1`.`normal_savings`.`amount`) from `normal_savings` where `jeramoyie1`.`normal_savings`.`member_id` = `m`.`id` and `jeramoyie1`.`normal_savings`.`transaction_type` = 'deposit'),0) - coalesce((select sum(`jeramoyie1`.`normal_savings`.`amount`) from `normal_savings` where `jeramoyie1`.`normal_savings`.`member_id` = `m`.`id` and `jeramoyie1`.`normal_savings`.`transaction_type` = 'withdrawal'),0)) AS `total_dividend_weight` from `members` `m`;
